INSERT INTO public.blends (code, name_ar, name_en, notes_ar, notes_en, roast_profile, sensory_profile, method_id, is_active, preparation_notes_ar, preparation_notes_en, manual_price, display_category, available_additive_ids) VALUES
('AP13', 'كونا آيرو', 'Kwna آYrw', 'تجربة استوائية ممتعة، تجمع بين نعومة الفانيليا وحلاوة الأناناس المنعشة.', 'Refreshing cup.\\nFlavor profile: pineapple, vanilla; bright acidity; full body.', NULL, '{"body": 5, "aroma": 4.5, "acidity": 3.5, "clarity": 3, "complexity": 4}', 'aeropress', 't', 'نقع 2:15 د، ماء 91°م', 'Steep; 2:15 min; water 91°C.', NULL, NULL, NULL),
('AP14', 'مونسونيد آيرو', 'Mwnswnyd آYrw', 'رحلة إلى الهند في فنجان، بنكهات التوابل الدافئة وحلاوة التمر الهندي اللاذعة.', 'A journey in a cup.\\nFlavor profile: date; low acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 2, "clarity": 2, "complexity": 5}', 'aeropress', 't', 'نقع 2 د، ماء 94°م', 'Steep; 2 min; water 94°C.', NULL, NULL, NULL),
('AP15', 'ألتورا آيرو', 'أLtwra آYrw', 'كوب مريح ودافئ، يجمع بين حلاوة الفول السوداني المحمص ودفء القرفة العطرية.', 'Comforting cup.\\nFlavor profile: cinnamon; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 3, "clarity": 3, "complexity": 4}', 'aeropress', 't', 'نقع 2:05 د، ماء 92°م', 'Steep; 2:05 min; water 92°C.', NULL, NULL, NULL),
('AP16', 'روبوستا بريميوم', 'Rwbwsta Brymywm', 'قوة مركزة، كوب بنكهة دخانية كلاسيكية وحلاوة الكراميل المحروق الداكن.', 'Signature cup.\\nFlavor profile: caramel; very low acidity; full body.', NULL, '{"body": 5, "aroma": 4, "acidity": 1, "clarity": 1, "complexity": 3}', 'aeropress', 't', 'نقع 2 د، ماء 96°م', 'Steep; 2 min; water 96°C.', NULL, NULL, NULL),
('AP17', 'أفريكان بلند آيرو', 'أFrykan Blnd آYrw', 'مزيج أفريقي معقد، يجمع بين حلاوة التين الداكنة ولمسة أنيقة من التوابل الحلوة.', 'Signature cup.\\nFlavor profile: high acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "acidity": 5, "clarity": 5, "complexity": 5}', 'aeropress', 't', 'نقع 2:10 د، ماء 93°م', 'Steep; 2:10 min; water 93°C.', NULL, NULL, NULL),
('AP18', 'توفي إثيوبيا', 'Twfy Ethiopia', 'فنجان إثيوبي نقي ومشرق، يجمع بين حمضية البرتقال ولمسة الزنجبيل المنعشة.', 'Refreshing cup.\\nFlavor profile: high acidity; light body.', NULL, '{"body": 2, "aroma": 5, "acidity": 5, "clarity": 5, "complexity": 4}', 'aeropress', 't', 'نقع 1:45 د، ماء 89°م', 'Steep; 1:45 min; water 89°C.', NULL, NULL, NULL),
('AP19', 'لواك ستايل آيرو', 'Lwak Stayl آYrw', 'تجربة كلاسيكية غنية، تجمع بين حلاوة التمر الداكنة وعمق النكهات الترابية الأصيلة.', 'Signature cup.\\nFlavor profile: date; very low acidity; full body.', NULL, '{"body": 5, "aroma": 4, "acidity": 1, "clarity": 2, "complexity": 4}', 'aeropress', 't', 'نقع 2:20 د، ماء 90°م', 'Steep; 2:20 min; water 90°C.', NULL, NULL, NULL),
('AP20', 'أرابيان نايتس', 'أRabyan Nayts', 'ليالٍ عربية في فنجان، يجمع بين حلاوة التمر الفاخرة ودفء الهيل العطري.', 'Luxurious cup.\\nFlavor profile: cardamom, date; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "acidity": 3, "clarity": 4, "complexity": 5}', 'aeropress', 't', 'نقع 2 د، ماء 92°م', 'Steep; 2 min; water 92°C.', NULL, NULL, NULL),
('B-001', 'أعماق إندونيسيا', 'أAmaq إNdwnysya', 'لدعم صحة العظام، مشروب قوي بنكهة عشبية ترابية عميقة.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 20 دقيقة + عرق سوس', 'Boil 20 min; add licorice.', NULL, NULL, NULL),
('B-002', 'روبوستا المعدلة', 'Rwbwsta Almadla', 'طاقة عالية جداً، مشروب قوي ومر بنكهة عشبية جريئة.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 2, "flavor": 3.5, "bitterness": 4}', 'boiling', 't', 'غلي 15 دقيقة + قرفة', 'Boil 15 min; add cinnamon.', NULL, NULL, NULL),
('B-003', 'التوفير الذهبي', 'Altwfyr Alihby', 'لزيادة الأيض، مشروب قوي بنكهة عشبية مع لمسة ترابية.', 'Bold cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 12 دقيقة + هيل', 'Boil 12 min; add cardamom.', NULL, NULL, NULL),
('B-004', 'اليقظة الآسيوية', 'Alyqza AlآSywya', 'لتركيز فوري، مشروب قوي جداً بنكهة عشبية ترابية.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 15 دقيقة + فلفل وردي', 'Boil 15 min; add pink pepper.', NULL, NULL, NULL),
('B-005', 'إندونيسي الدبس', 'إNdwnysy Aldbs', 'لطاقة وقوة بدنية، مشروب قوي جداً بنكهة عشبية ترابية عميقة.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 25 دقيقة + دبس رمان', 'Boil 25 min; add pomegranate molasses.', NULL, NULL, NULL),
('B-006', 'طاقة التمرين', 'Taqa Altmryn', 'لأداء رياضي عالي، مشروب قوي بنكهة عشبية جريئة.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 10 دقائق + زنجبيل طازج', 'Boil 10 min; add fresh ginger, ginger.', NULL, NULL, NULL),
('B-007', 'القوة الآسيوية المعدلة', 'Alqwa AlآSywya Almadla', 'لطاقة قصوى، مشروب قوي ومر جداً بنكهة عشبية.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 2, "aroma": 2, "flavor": 2.5, "bitterness": 4}', 'boiling', 't', 'غلي 15 دقيقة + قشر برتقال', 'Boil 15 min; add orange peel.', NULL, NULL, NULL),
('B-008', 'إندونيسي المميز', 'إNdwnysy Almmyz', 'لدعم صحة المفاصل، مشروب قوي بنكهة عشبية ترابية عميقة.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 3, "aroma": 3, "flavor": 3, "bitterness": 4}', 'boiling', 't', 'غلي 30 دقيقة + جوزة الطيب', 'Boil 30 min; add nutmeg.', NULL, NULL, NULL),
('B-009', 'مناعة الشرق', 'Mnaaa Alshrq', 'لتعزيز المناعة، مشروب يجمع بين النكهات العشبية الفاكهية والقوية.', 'Bold cup.Flavor profile: medium-full body.', NULL, '{"body": 4, "Color": 3, "aroma": 3, "flavor": 4, "bitterness": 3}', 'boiling', 't', 'غلي 15 دقيقة + قرفة', 'Boil 15 min; add cinnamon.', NULL, NULL, NULL),
('B-010', 'متانة الروبوستا', 'Mtana Alrwbwsta', 'لقوة تحمل عالية، مشروب قوي ومر جداً بنكهة عشبية.', 'Bold cup.\\nFlavor profile: full body.', NULL, '{"body": 5, "Color": 2, "aroma": 2, "flavor": 3, "bitterness": 5}', 'boiling', 't', 'غلي 25 دقيقة + فانيليا', 'Boil 25 min; add vanilla.', NULL, NULL, NULL),
('turkish_classic', 'توليفة التركي الكلاسيكية', 'Classic Turkish Blend', 'كلاسيكي، مكسرات، شوكولاتة', 'Classic, Nuts, Chocolate', NULL, '{"body": 4, "power": 4, "sweetness": 3, "bitterness": 3, "face_cream": 5}', 'turkish', 't', 'استخدم ماء بارد، أضف السكر حسب الرغبة قبل التسوية، لا تتركها تغلي طويلاً للحفاظ على الوش', 'Use cold water, Add sugar to taste before brewing, Do not let it boil for too long to preserve the crema', NULL, NULL, NULL),
('v60_ethiopian_sun', 'شمس إثيوبيا (V60)', 'Ethiopian Sun (V60)', 'زهور، ليمون، توت أزرق', 'Floral, Lemon, Blueberry', NULL, '{"body": 2, "aroma": 4, "acidity": 5, "clarity": 5, "complexity": 4}', 'v60', 't', 'نسبة التحضير 1:16 (قهوة إلى ماء)، درجة حرارة الماء 94 درجة مئوية، صب الماء على دفعات دائرية', 'Brew ratio 1:16 (coffee to water), Water temperature 94°C, Pour in circular motions', NULL, NULL, NULL),
('french_press_bold', 'فرنش برس الجريئة', 'Bold French Press', 'كاكاو، مكسرات محمصة، ترابي', 'Cocoa, Toasted Nuts, Earthy', NULL, '{"body": 5, "aroma": 3, "acidity": 3, "clarity": 2, "complexity": 3}', 'french-press', 't', 'استخدم طحنة خشنة، نقع لمدة 4 دقائق، اضغط المكبس ببطء', 'Use a coarse grind, Steep for 4 minutes, Press the plunger slowly', NULL, NULL, NULL),
('cold_brew_smooth', 'كولد برو السلس', 'Smooth Cold Brew', 'شوكولاتة بالحليب، كراميل، فانيلا', 'Milk Chocolate, Caramel, Vanilla', NULL, '{"body": 3, "intensity": 3, "sweetness": 4, "smoothness": 5, "acid_clarity": 2}', 'cold-brew', 't', 'نقع لمدة 12-18 ساعة في الثلاجة، استخدم طحنة خشنة جداً، قم بتصفيته جيداً قبل التقديم', 'Steep for 12-18 hours in the refrigerator, Use a very coarse grind, Filter well before serving', NULL, NULL, NULL),
('B-011', 'فجر أفريقيا', 'Fjr أFryqya', 'للنشاط والحيوية، مشروب يجمع بين النكهات العشبية القوية والمشرقة.', 'Bold cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "Color": 4, "aroma": 4, "flavor": 4, "bitterness": 3}', 'boiling', 't', 'غلي 10 دقائق + توت مجفف', 'Boil 10 min; add dried berries.', NULL, NULL, NULL),
('B-012', 'العمق البرازيلي', 'Alamq Albrazyly', 'لصحة القلب، مشروب بنكهة عشبية كلاسيكية وقوام ممتلئ.', 'Signature cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "Color": 4, "aroma": 4, "flavor": 4, "bitterness": 3}', 'boiling', 't', 'غلي 15 دقيقة + كاكاو خام', 'Boil 15 min; add raw cacao.', NULL, NULL, NULL),
('espresso_intenso', 'إسبريسو إنتنسو', 'Espresso Intenso', 'شوكولاتة داكنة، كراميل، توابل', 'Dark Chocolate, Caramel, Spices', NULL, '{"body": 4, "crema": 5, "balance": 3, "intensity": 5, "aftertaste": 4}', 'espresso', 'f', 'درجة حرارة الماء 92-94 درجة مئوية، استخلاص لمدة 25-30 ثانية، استخدم بن مطحون حديثاً', 'Water temperature 92-94°C, Extraction time 25-30 seconds, Use freshly ground beans', NULL, NULL, NULL),
('FUNC_DWN', 'ديوان', 'Diwan', 'قهوة ضيافة فاخرة وكلاسيكية.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة: ٣٠ جرام هيل أخضر فاخر، خيط أو اثنين من الزعفران الأصلي.', '', NULL, 'وظيفية', NULL),
('FUNC_DFE', 'دفء', 'Warmth', 'مزيج شتوي كلاسيكي مع ثلاثية توابل دافئة.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة: ١٥ جرام قرفة، ١٠ جرام قرنفل، ٥ جرام جوزة الطيب.', '', NULL, 'وظيفية', NULL),
('FUNC_BRKN', 'بركان', 'Volcano', 'قهوة قوية ذات كافيين عالٍ ونكهة خام.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة: ٢٠ جرام جذور الشيكوريا المحمصة (اختياري)، ١٠ جرام فلفل أسود مطحون.', '', NULL, 'وظيفية', NULL),
('FUNC_ELHM', 'إلهام', 'Inspire', 'قهوة ذات تعقيد فاكهي وتابلي مميز.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة: ١٥ جرام قشر برتقال مجفف، ٥ جرام يانسون نجمي مطحون.', '', NULL, 'وظيفية', NULL),
('FUNC_HDO', 'هدوء', 'Calm', 'كوب قهوة كريمي وناعم جداً، مع رائحة الفانيليا وجوزة الطيب المريحة للأعصاب.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة (لكل كيلو بن): ١٥ جرام فانيليا طبيعية، ٥ جرام بابونج (اختياري)، رشة خفيفة من جوزة الطيب.', '', NULL, 'وظيفية', NULL),
('FUNC_HDM', 'هضم', 'Digest', 'قهوة مريحة للمعدة بعد الأكل.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة: ٢٠ جرام يانسون، ١٠ جرام بذور شمر.', '', NULL, 'وظيفية', NULL),
('FUNC_ESHRQ', 'إشراقة', 'Sunrise', 'قهوة صباحية متوازنة وكلاسيكية.', NULL, NULL, NULL, NULL, 't', 'تحويجة خاصة: ١٥ جرام هيل، ٥ جرام مستكة (اختياري).', NULL, NULL, 'وظيفية', NULL),
('green_detox', 'القهوة الخضراء ديتوكس', 'Green Detox Coffee', 'عشبي، شاي أخضر، خفيف', 'Herbal, Green Tea, Light', NULL, '{"body": 2, "aroma": 2, "color": 3, "flavor": 3, "bitterness": 2}', 'green', 'f', 'يمكن نقعه في ماء بارد لمدة ساعتين، يمكن غليه وتصفيته، يقدم بارداً أو ساخناً', 'Can be soaked in cold water for 2 hours, Can be boiled and filtered, Serve cold or hot', NULL, NULL, NULL),
