('V08', 'سيرادو كلاسيك', 'Cerrado Classic', 'فنجان كلاسيكي أصيل، يجمع بين نكهة البندق المحمص والكراميل المملح في توازن مثالي.', 'Signature cup.\\nFlavor profile: caramel, hazelnut; low acidity; medium-full body.', NULL, '{"body": 4, "aroma": 3, "acidity": 2, "clarity": 3, "complexity": 2}', 'v60', 't', 'ماء 92°م، 2:30 د', 'water 92°C; 2:30 min', NULL, NULL, NULL),
('V09', 'تشانشامايو فروت', 'Tshanshamayw Frwt', 'مغامرة استوائية ممتعة، بنكهات الفواكه المنعشة التي تكتمل بحلاوة الشوكولاتة البيضاء الناعمة.', 'Refreshing cup.\\nFlavor profile: chocolate; bright acidity; medium body.', NULL, '{"body": 3, "aroma": 3, "acidity": 4, "clarity": 4, "complexity": 3}', 'v60', 't', 'صب مزدوج، ماء 90°م', 'Double pour; water 90°C', NULL, NULL, NULL),
('V10', 'مانديلينج المعدلة', 'Mandheling Almadla', 'تجربة جريئة وعميقة، تتميز بنكهة التوت الداكن الغنية مع لمسة ترابية أصيلة وقوام ممتلئ.', 'Signature cup.\\nFlavor profile: berry; low acidity; full body.', NULL, '{"body": 5, "aroma": 4, "acidity": 2, "clarity": 3, "complexity": 4}', 'v60', 't', 'ماء 94°م، صب كثيف', 'intense; water 94°C', NULL, NULL, NULL),
('V11', 'دا لات إنتنس', 'Da Lat إNtns', 'لمحبي القهوة القوية، كوب جريء بنكهة خشب الأرز والكراميل المحروق وقوام ثقيل يدوم.', 'Bold cup.\\nFlavor profile: caramel; very low acidity; full body.', NULL, '{"body": 5, "aroma": 3, "acidity": 1, "clarity": 1, "complexity": 2}', 'v60', 't', 'صب سريع، ماء 95°م', 'fast; water 95°C', NULL, NULL, NULL),
('V12', 'أوغندا سيك', 'أWghnda Syk', 'فنجان معقد وممتع، يجمع حلاوة الفواكه المجففة مع عمق الكاكاو ونهاية تشبه نكهة العنب الأحمر.', 'Signature cup.\\nFlavor profile: cocoa; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 3, "clarity": 3, "complexity": 4}', 'v60', 't', 'صب متدرج، ماء 93°م', 'Staged pour; water 93°C', NULL, NULL, NULL),
('V13', 'كينيا بلند', 'Kynya Blnd', 'مزيج قوي ومتطور، يجمع بين حمضية العنب الأسود الكيني ولمسة دافئة من التوابل الوردية.', 'Bold cup.\\nFlavor profile: high acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 5, "clarity": 4, "complexity": 5}', 'v60', 't', 'صب دائري مكثف، ماء 92°م', 'Circular pour (intense); water 92°C', NULL, NULL, NULL),
('V14', 'كونا هاواي', 'Kwna Hawaii', 'إحساس استوائي دافئ، يجمع بين حلاوة الفانيليا الكريمية ونكهة الأناناس المنعشة.', 'Refreshing cup.\\nFlavor profile: pineapple, vanilla; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 3, "clarity": 3, "complexity": 3}', 'v60', 't', 'وقت 3 دقائق، ماء 91°م', 'water 91°C; 3 min', NULL, NULL, NULL),
('V15', 'سيدامو العطرية', 'Sidamo Alatrya', 'عطر من الياسمين والليمون في فنجانك، مع نقاء ونعومة الشاي الأخضر الفاخر.', 'Luxurious cup.\\nFlavor profile: jasmine; high acidity; light body.', NULL, '{"body": 2, "aroma": 5, "acidity": 5, "clarity": 5, "complexity": 4}', 'v60', 't', 'صب بطيء، ماء 89°م', 'slow; water 89°C', NULL, NULL, NULL),
('V16', 'مونسونيد الهند', 'Mwnswnyd Alhnd', 'تجربة هندية فريدة، بنكهات التوابل الغنية ولمسة العنبر الدافئة التي تأخذك في رحلة إلى الشرق.', 'A journey in a cup.\\nFlavor profile: low acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 2, "clarity": 2, "complexity": 5}', 'v60', 't', 'صب سريع، ماء 94°م', 'fast; water 94°C', NULL, NULL, NULL),
('V17', 'بورسيرون البرازيل', 'Bwrsyrwn Albrazyl', 'فنجان كريمي ومريح، يجمع بين حلاوة شوكولاتة الحليب ونكهة جوز البقان الغنية.', 'Comforting cup.\\nFlavor profile: pecan, chocolate; balanced acidity; full body.', NULL, '{"body": 5, "aroma": 4, "acidity": 3, "clarity": 3, "complexity": 4}', 'v60', 't', 'صب حلزوني مكثف، ماء 93°م', 'Spiral pour (intense); water 93°C', NULL, NULL, NULL),
('V18', 'جيشا كولومبيا', 'Jysha Colombia', 'قمة الفخامة، فنجان نادر بنكهات البرتقال والبرغموت العطرية وحلاوة عسل السدر الصافي.', 'Signature cup.\\nFlavor profile: honey; high acidity; light body.', NULL, '{"body": 2, "aroma": 5, "acidity": 5, "clarity": 5, "complexity": 4}', 'v60', 't', 'صب دقيق، ماء 88°م', 'water 88°C', NULL, NULL, NULL),
('V19', 'ألتورا المكسيك', 'أLtwra Almksyk', 'كوب دافئ ومريح، يجمع حلاوة الفواكه المجففة مع لمسة عطرية من القرفة الدافئة.', 'Comforting cup.\\nFlavor profile: cinnamon; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 4, "acidity": 3, "clarity": 3, "complexity": 4}', 'v60', 't', 'صب طبقي، ماء 92°م', 'Layered pour; water 92°C', NULL, NULL, NULL),
('V20', 'روبوستا بريميوم+', 'Rwbwsta Brymywm+', 'قوة وتركيز في فنجان واحد، يجمع بين مرارة الكاكاو الداكن واللمسة الدخانية مع حمضية خفيفة في النهاية.', 'Signature cup.\\nFlavor profile: cocoa; balanced acidity; full body.', NULL, '{"body": 5, "aroma": 3, "acidity": 3, "clarity": 2, "complexity": 3}', 'v60', 't', 'صب سريع، ماء 96°م', 'fast; water 96°C', NULL, NULL, NULL),
('V21', 'بيرو أورجانيك', 'Byrw أWrjanyk', 'فنجان عضوي نقي، يتميز بحلاوة الكراميل الطبيعية ونكهة المكسرات مع حمضية ناعمة ومتوازنة.', 'Signature cup.\\nFlavor profile: caramel; bright acidity; medium body.', NULL, '{"body": 3, "aroma": 3, "acidity": 4, "clarity": 4, "complexity": 3}', 'v60', 't', 'صب مزدوج، ماء 91°م', 'Double pour; water 91°C', NULL, NULL, NULL),
('V22', 'V60 كولد برو بالعسل', 'V60 Cold Brew Balasl', 'مشروب بارد ومنعش، يجمع بين عمق الشوكولاتة وعطرية الزهور مع حلاوة العسل الطبيعي.', 'Refreshing cup.\\nFlavor profile: chocolate, honey, floral; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "acidity": 3, "clarity": 4, "complexity": 5}', 'v60', 't', 'نقع 18 ساعة، يضاف العسل عند التقديم', 'Steep; 18 hrs; add honey at serve', NULL, NULL, NULL),
('CB20', 'أرابيان آيسد', 'أRabyan آYsd', 'ليالٍ عربية باردة، يجمع بين حلاوة التمر الفاخرة ولمسة من الزعفران والهيل.', 'Luxurious cup.\\nFlavor profile: saffron, cardamom, date; balanced acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "acidity": 3, "clarity": 4, "softness": 3, "intensity": 3, "sweetness": 3, "complexity": 5, "acidity_clarity": 3}', 'cold-brew', 't', 'نقع 18 ساعة + هيل', 'Cold steep; 18 hrs; add cardamom.', NULL, NULL, NULL),
('TRB-001', 'ميدان التحرير', 'Mydan Althryr', 'فنجان متوازن وحيوي، يجمع بين الكراميل والمكسرات والشوكولاتة.', 'Signature cup.\\nFlavor profile: caramel, chocolate; bright acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "crema": 4, "flavor": 5, "acidity": 4, "bitterness": 1.5}', 'turkish', 't', NULL, NULL, NULL, NULL, NULL),
('FP03', 'أصل سيدامو', 'Origin Sidamo', 'تجربة إثيوبية عطرية، كأنك في حقل من الزهور البرية مع حمضية الليمون المنعشة.', 'Refreshing cup.\\nFlavor profile: floral; high acidity; light body.', NULL, '{"body": 2, "aroma": 5, "acidity": 5, "clarity": 3, "complexity": 4}', 'french-press', 't', 'نقع 4 دقائق، ماء 90°م', 'Steep; 4 min; water 90°C.', NULL, NULL, NULL),
('CS-016', 'أطلس المتوسط', 'أTls Almtwst', 'لتركيز ووضوح ذهني، مشروب يجمع بين النكهات العشبية والفاكهية.', 'Signature cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "Color": 4, "aroma": 4, "color": 3, "flavor": 4, "bitterness": 3}', 'cold-infusion', 't', 'نقع 36 ساعة بنسبة 1:12', 'Cold soak 36 hrs; ratio 1:12.', NULL, NULL, NULL),
('CS-007', 'أفرو-آسيوي', 'أFrw-آSywy', 'للطاقة والتركيز، مشروب قوي بنكهة عشبية جريئة ولمسة ترابية.', 'Bold cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "Color": 3, "aroma": 3, "flavor": 4, "bitterness": 4}', 'cold-infusion', 't', 'نقع 18 ساعة + كاكاو خام', 'Cold soak 18 hrs; add raw cacao.', NULL, NULL, NULL),
('FUNC_TRKZ', 'تركيز', 'Focus', 'رائحة دافئة من التوابل، مع مذاق متوازن يجمع حلاوة الشوكولاتة والكراميل، ونهاية ترابية خفيفة من الجنسنج.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة (لكل كيلو بن): ١٥ جرام قرفة، ١٠ جرام هيل، ٥ جرام جوزة الطيب، ٥ جرام مسحوق الجنسنج.', '', NULL, 'وظيفية', NULL),
('FUNC_SHGF', 'شغف', 'Passion', 'تجربة عطرية فاخرة، مع طعم معقد يجمع بين حلاوة التمر والزيبيب، ورائحة الورد والزعفران، معززة بنهاية دافئة وحيوية من الجنسنج.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة (لكل كيلو بن): ٢٠ جرام هيل فاخر، رشة زعفران، ٥ جرام بتلات ورد، ١٠ جرام مسحوق الجنسنج.', '', NULL, 'وظيفية', NULL),
('ESP-48', 'آيس بلند', 'آYs Blnd', 'المزيج المثالي للقهوة الباردة، إسبريسو يقطع الحليب بنكهات الفانيليا وجوز الهند والكراميل.', 'Signature cup.\\nFlavor profile: caramel, vanilla; full body.', NULL, '{"body": 5, "crema": 3, "balance": 4, "intensity": 5, "aftertaste": 4}', 'espresso', 't', '', '', NULL, NULL, NULL),
('FUNC_PWR', 'باور', 'Power', 'طعم قوي ولاذع، مع مرارة واضحة وركلة كافيين قوية، معززة بالإحساس الدافئ من الزنجبيل والقوة الترابية من الجنسنج.', '', NULL, '{}', NULL, 't', 'تحويجة خاصة (لكل كيلو بن): ٢٠ جرام زنجبيل، ١٠ جرام قرنفل، ١٥ جرام مسحوق الجنسنج.', '', NULL, 'وظيفية', NULL),
('TRB-098', 'أبو الهول', 'أBw Alhwl', 'غموض أبو الهول، فنجان يجمع بين حمضية التفاح الأخضر المشرقة وحلاوة العسل.', 'Signature cup.\\nFlavor profile: honey, apple; high acidity; medium-full body.', NULL, '{"body": 4.5, "aroma": 4, "crema": 4, "flavor": 5, "acidity": 5, "bitterness": 2}', 'turkish', 't', '', '', NULL, NULL, NULL),
('ESP-10', 'التحميصة الذهبية', 'Althmysa Alihbya', 'إسبريسو متوازن وكلاسيكي، يجمع بين نكهة الكاجو والخبز المحمص مع حلاوة خفيفة وكريمة ذهبية.', 'Signature cup.\\nFlavor profile: medium-full body.', NULL, '{"body": 4, "crema": 3, "balance": 4, "intensity": 4.5, "aftertaste": 4}', 'espresso', 't', '', '', NULL, NULL, NULL),
('CB06', 'أنتيغوا آيس', 'Antigua آYs', 'مشروب بارد وغني، يجمع بين حلاوة الكرز الداكن وعمق الشوكولاتة الفاخرة.', 'Luxurious cup.\\nFlavor profile: chocolate; low acidity; full body.', NULL, '{"body": 5, "aroma": 4, "acidity": 2, "clarity": 3, "complexity": 4}', 'cold_brew', 't', 'نقع 16 ساعة', 'Cold steep; 16 hrs.', NULL, NULL, NULL),
('TRB-208', 'أسوان', 'Aswan', 'دفء أسوان في فنجان، يجمع بين حلاوة التين المجفف والتوابل الدافئة وعمق الكاكاو.', 'Comforting cup.\\nFlavor profile: cocoa; bright acidity; medium-full body.', NULL, '{"body": 4.5, "aroma": 5, "crema": 4, "flavor": 5, "acidity": 4, "bitterness": 1}', 'turkish', 't', '', '', NULL, NULL, NULL),
('ESP-16', 'أصل هرر', 'Origin Hrr', 'إسبريسو إثيوبي أصيل، يجمع بين حلاوة البرقوق ونكهات الأعشاب العطرية ورائحة زهور البرتقال.', 'Signature cup.\\nFlavor profile: floral; medium body.', NULL, '{"body": 3, "crema": 3, "balance": 5, "intensity": 3, "aftertaste": 4}', 'espresso', 't', '', '', NULL, NULL, NULL),
('CB10', 'أفريكان كولد', 'أFrykan Cold', 'احتفال أفريقي بارد، يجمع بين حمضية اليوسفي المنعشة ولمسة الزنجبيل الحارة.', 'Refreshing cup.\\nFlavor profile: bright acidity; medium body.', NULL, '{"body": 3, "aroma": 5, "acidity": 4, "clarity": 5, "softness": 3, "intensity": 3, "sweetness": 3, "complexity": 5, "acidity_clarity": 3}', 'cold-brew', 't', 'نقع 20 ساعة + قشر برتقال', 'Cold steep; 20 hrs; add orange peel.', NULL, NULL, NULL),
('FP20', 'أفريكان بلند', 'أFrykan Blnd', 'مزيج أفريقي معقد، يجمع بين حلاوة التين الداكنة ولمسة أنيقة من التوابل الحلوة.', 'Signature cup.\\nFlavor profile: high acidity; medium-full body.', NULL, '{"body": 4, "aroma": 5, "acidity": 5, "clarity": 5, "complexity": 5}', 'french-press', 't', 'نقع 4:30 د، تقليب مكثّف', 'Steep; 4:30 min; vigorous stir.', NULL, NULL, NULL),
('CS-001', 'أفريكان فروت', 'أFrykan Frwt', 'مشروب صحي غني بمضادات الأكسدة، بنكهة فاكهية طبيعية ولمسة عشبية منعشة.', 'Refreshing cup.\\nFlavor profile: medium body.', NULL, '{"body": 3, "Color": 5, "aroma": 5, "color": 3, "flavor": 5, "bitterness": 2}', 'cold-infusion', 't', 'نقع 24 ساعة في الثلاجة', 'Cold soak 24 hrs refrigerated.', NULL, NULL, NULL);
