INSERT INTO public.site_content (key, value, updated_at) VALUES
('about_us', '{"title_ar": "من نحن؟", "title_en": "About Us", "content_ar": "في تَولِيفتِي™، نحن نؤمن بأن القهوة أكثر من مجرد مشروب؛ إنها تجربة. مهمتنا هي تمكين كل محب للقهوة من اكتشاف وصنع توليفتهم المثالية التي تناسب ذوقهم الفريد.", "content_en": "At Tawlefti™, we believe that coffee is more than just a drink; it''s an experience. Our mission is to empower every coffee lover to discover and create their perfect blend that suits their unique taste."}', '2025-08-12 16:54:24.918062+00'),
('contact_us', '{"title_ar": "اتصل بنا", "title_en": "Contact Us", "content_ar": "للاستفسارات أو الدعم، يرجى التواصل معنا عبر البريد الإلكتروني: support@tawlefti.com او الواتساب  01119996549", "content_en": "For inquiries or support, please contact us via email: support@tawlefti.com  or WhatsApp: +2 01119996549 "}', '2025-08-12 16:54:24.918062+00'),
('faq', '{"items": [{"a_ar": "ببساطة، اختر طريقة التحضير المفضلة لديك، ثم اضبط مؤشرات النكهة لتصفية التوليفات التي تناسب ذوقك. يمكنك بعد ذلك تخصيص طلبك وإضافته إلى السلة.", "a_en": "Simply choose your favorite preparation method, then adjust the flavor sliders to filter blends that suit your taste. You can then customize your order and add it to the cart.", "q_ar": "كيف يعمل التطبيق؟", "q_en": "How does the app work?"}, {"a_ar": "تعتمد مدة التوصيل على موقعك. بشكل عام، يتم توصيل الطلبات داخل الاسكندرية  خلال 2-3 ساعة.", "a_en": "Delivery time depends on your location. Generally, orders within Alexandria are delivered within 2-3 hours.", "q_ar": "ما هي مدة توصيل الطلبات؟", "q_en": "How long does delivery take?"}], "title_ar": "الأسئلة الشائعة", "title_en": "Frequently Asked Questions"}', '2025-08-12 16:54:24.918062+00');
